import { Job } from 'bull';

@Processor('email')
export class EmailConsumer {
  @Process('send-confirmation')
  async handleSendConfirmation(job: Job) {
    const { orderId, userEmail } = job.data;
    // Logique d'envoi d'email (via Nodemailer, etc.)
    console.log(`Envoi d'email pour la commande ${orderId} à ${userEmail}`);
    // Simuler l'envoi
    await new Promise(resolve => setTimeout(resolve, 1000));
  }
}
